INSERT INTO payment_instructions (payment_method_id, title, content, sort_order) VALUES
(2, 'Pembayaran via Mbanking', '<ol><li>Open BCA Mobile App</li><li>Select m-BCA, then select m-Transfer</li><li>Enter your Virtual Account Number, for example 3816523906568, then press OK</li><li>Click on Send button at the top right corner to proceed</li><li>Click OK to proceed</li><li>Enter your PIN to authorize the transaction</li></ol>', 1),
(2, 'Pembayaran via Ibanking', '<ol><li>Login to KlikBCA Individual (https://ibank.klikbca.com)</li><li>Select Transfer, then select Transfer to BCA Virtual Account</li><li>Enter the Virtual Account Number, for example 3816523906568</li><li>Select Continue to proceed your payment</li><li>Enter RESPON KEYBCA APPLI 1 shown in your BCA Token, then click on the Send button</li><li>Enter the authentication token code</li></ol>', 2),
(2, 'Pembayaran via Atm', '<ol><li>Insert your BCA ATM card and PIN</li><li>Enter your ATM PIN</li><li>Select Menu Other Transaction</li><li>Select Transfer</li><li>Select To BCA Virtual Account</li><li>Enter Virtual Account Number, for example 3816523906568. Press Correct to proceed</li><li>Verify Virtual Account details and then enter amount to be transferred and select Correct to confirm</li><li>Confirm your transaction details displayed</li><li>Select Yes if the details are correct or No if the details are not correct</li></ol>', 3),
(3, 'Pembayaran via Livin', '<ol><li>Log in to Livin’ by Mandiri app</li><li>Select IDR Transfer > Transfer to new recipient</li><li>Enter virtual account number (e.g. 8860863623046)</li><li>Enter or confirm payment amount</li><li>Click Continue</li><li>Enter MPIN</li></ol>', 4),
(3, 'Pembayaran via Atm', '<ol><li>Insert ATM Card</li><li>Select preferred language</li><li>Enter ATM PIN</li><li>Select PAYMENT > MULTI PAYMENT</li><li>Enter company code 88608 (XENDIT), then press CORRECT</li><li>Enter virtual account number (e.g. 8860863623046), then press CORRECT</li><li>Enter payment amount, then press CORRECT</li><li>Confirm payment details</li></ol>', 5),
(9, 'Pembayaran via Brimo', '<ol><li>Log in to BRI Mobile Banking</li><li>Select Payment > Briva</li><li>Enter virtual account number (e.g. 1328216932121)</li><li>Enter payment amount</li><li>Enter PIN</li><li>Tap Send</li></ol>', 6),
(9, 'Pembayaran via Atm', '<ol><li>Insert ATM Card</li><li>Select preferred language</li><li>Enter ATM PIN</li><li>Select Other Menu > Payment > Other Payment > BRIVA</li><li>Enter virtual account number (e.g. 1328216932121)</li><li>Enter payment amount</li><li>Confirm payment details and press YES</li></ol>', 7),
(10, 'Pembayaran via Mobile', '<ol><li>Log in to BNI mobile banking app</li><li>Click Transfer > Virtual Account Billing, then choose debit account</li><li>Enter virtual account number (e.g. 880849021633)</li><li>Payment amount will be displayed on the screen</li><li>Confirm payment information</li><li>Enter password</li></ol>', 8),
(10, 'Pembayaran via Ibanking', '<ol><li>Log in to https://ibank.bni.co.id</li><li>Click Transfer > Virtual Account Billing</li><li>Enter virtual account number (e.g. 880849021633)</li><li>Choose bank account</li><li>Payment amount will be displayed on the screen</li><li>Enter authentication token code</li></ol>', 9),
(10, 'Pembayaran via Atm', '<ol><li>Insert ATM Card</li><li>Select preferred language</li><li>Enter ATM PIN</li><li>Select Other Transaction > Transfer</li><li>Choose account type</li><li>Enter virtual account number (e.g. 880849021633)</li><li>Payment amount will be displayed on the screen</li><li>Confirm payment information</li></ol>', 10),
(11, 'Pembayaran via Mobile', '<ol><li>Open BJB Mobile app</li><li>Enter User ID and Password</li><li>Choose Virtual Account</li><li>Select the type of account you are using to transfer (i.e. from Savings account)</li><li>Enter Virtual Account Number, for example 1234999968795947</li><li>Confirm your transaction details displayed</li></ol>', 11),
(11, 'Pembayaran via Ibanking', '<ol><li>Open https://ib.bankbjb.co.id/bjb.net</li><li>Enter User ID and Password</li><li>Select Virtual Account</li><li>Select the type of account you are using to transfer (i.e. from Savings account)</li><li>Enter Virtual Account Number, for example 1234999968795947</li><li>Confirm your transaction details displayed</li></ol>', 12),
(11, 'Pembayaran via Atm', '<ol><li>Insert your BJB ATM card and PIN</li><li>Enter your ATM PIN</li><li>Select Menu Transaksi Lainnya</li><li>Select Virtual Account</li><li>Select the type of account you are using to transfer (i.e. from Savings account)</li></ol>', 13),
(12, 'Pembayaran via Mobile', '<ol><li>Log in to BNC mobile banking or Neobank app</li><li>Click Hematpay VA & QRIS</li><li>Enter virtual account number (e.g. 9010001050411994)</li><li>Enter payment amount</li><li>Confirm payment information</li><li>Enter PIN</li></ol>', 14),
(12, 'Pembayaran via Atm', '<ol><li>Insert ATM Card</li><li>Select preferred language</li><li>Enter ATM PIN</li><li>Select Pembayaran VA</li><li>Enter virtual account number (e.g. 9010001050411994)</li><li>Enter payment amount</li><li>Confirm payment information</li><li>Enter PIN</li></ol>', 15),
(4, 'Pembayaran via Byond', '<ol><li>Log in to BYOND BSI</li><li>Choose Bayar & Beli</li><li>Search Xendit, Choose Prefix VA: 9347 or 9655</li><li>Insert code (without prefix) (e.g. 33371937)</li><li>Enter PIN</li><li>Confirm payment details</li></ol>', 16),
(4, 'Pembayaran via Ibanking', '<ol><li>Log in to https://bsinet.bankbsi.co.id</li><li>Click Payment</li><li>Choose source of payment</li><li>Click Institution</li><li>Enter Xendit as institution name (code 9347)</li><li>Enter virtual account number (e.g. 33371937)</li><li>Confirm payment details</li><li>Enter authentication token code</li></ol>', 17),
(4, 'Pembayaran via Atm', '<ol><li>Insert ATM Card</li><li>Select preferred language</li><li>Enter ATM PIN</li><li>Select Payment/Purchase > Institution</li><li>Enter virtual account number (e.g. 934733371937)</li><li>Confirm payment details</li></ol>', 18),
(4, 'Pembayaran via Antarbank', '<ol><li>Log in to your bank Account</li><li>Click Transfer > Choose BSI</li><li>Enter 009 + BSI Virtual Account code 9347 + virtual account number, (e.g. 934733371937)</li><li>Enter payment amount</li><li>Select source of payment</li><li>Choose Online Transfer</li><li>Confirm payment details</li></ol>', 19),
(13, 'Pembayaran via Octo', '<ol><li>Open Octo Mobile and enter your User ID and Password</li><li>Select the menu Transfer and then choose Other CIMB Niaga</li><li>Enter your Virtual Account Number on the menu Input New</li><li>Input the payment amount accordingly</li><li>Confirm the transaction and enter your password</li><li>Your transaction is completed</li></ol>', 20),
(13, 'Pembayaran via Atm', '<ol><li>Insert your ATM Card</li><li>Select your preferred language</li><li>Enter your ATM PIN</li><li>Select the menu Transfer and then choose Other CIMB Niaga</li><li>Enter your Virtual Account Number on the menu Input New</li><li>Input the payment amount accordingly</li><li>Confirm the transaction and enter your password</li><li>Your transaction is completed</li></ol>', 21),
(13, 'Pembayaran via Ibanking', '<ol><li>Enter the following address https://www.octoclicks.co.id/login and click Enter</li><li>Enter User ID and Password</li><li>Select the menu Transfer and then choose Other CIMB Niaga</li><li>Enter your Virtual Account Number on the menu Input New</li><li>Input the payment amount accordingly</li><li>Confirm the transaction and enter your password</li><li>Your transaction is completed</li></ol>', 22),
(14, 'Pembayaran via Mdin', '<ol><li>Log in to MDIN mobile banking</li><li>Select Beli/Bayar > Beli/Bayar Tagihan > Virtual Account</li><li>Enter virtual account number (e.g. 9010001112341234234)</li><li>Enter payment amount</li><li>Confirm payment details</li><li>Enter PIN</li></ol>', 23),
(14, 'Pembayaran via Ibanking', '<ol><li>Log in to Muamalat Internet Banking</li><li>Click Payment > Virtual Account</li><li>Enter virtual account number (e.g. 9010001112341234234)</li><li>Enter payment amount</li><li>Confirm payment details</li><li>Enter PIN</li></ol>', 24),
(14, 'Pembayaran via Atm', '<ol><li>Insert ATM Card</li><li>Select preferred language</li><li>Enter ATM PIN</li><li>Select Pembayaran > Virtual Account</li><li>Enter virtual account number (e.g. 9010001112341234234)</li><li>Enter payment amount</li><li>Confirm payment details</li><li>Enter PIN</li></ol>', 25),
(15, 'Pembayaran via Mobile', '<ol><li>Log in to Permata mobile app</li><li>Select Pembayaran Tagihan > Virtual Account</li><li>Enter virtual account number (e.g. 729361827494)</li><li>Enter authentication token</li></ol>', 26),
(15, 'Pembayaran via Ibanking', '<ol><li>Log in to https://www.permatanet.com</li><li>Select Pembayaran Tagihan > Virtual Account</li><li>Enter virtual account number (e.g. 729361827494)</li><li>Confirm payment details</li><li>Enter SMS token response code</li></ol>', 27),
(15, 'Pembayaran via Atm', '<ol><li>Insert ATM Card</li><li>Select preferred language</li><li>Enter ATM PIN</li><li>Select Transaksi Lainnya > Pembayaran > Pembayaran Lainnya > Virtual Account</li><li>Enter virtual account number (e.g. 729361827494)</li><li>Confirm payment details</li><li>Enter PIN</li></ol>', 28),
(16, 'Pembayaran via Note', '<ol><li>You can make a payment to the Alfamart Group (Alfamart, Afamidi, Dan+Dan, Lawson).</li><li>Payments below IDR 2,5 Million are available via Alfamart, Afamidi, Dan+Dan, Lawson.</li><li>Payments above IDR 2,5 Million are not available via Alfamidi.</li><li>Visit the nearest ALFAMART branch before the time on the payment code/barcode runs out</li><li>Tell the cashier that you would like to make a payment to “[Merchant Name]” via Xendit or let them scan the barcode above</li><li>Present the payment code/barcode to the cashier and confirm that the amount is correct</li><li>Inform the cashier if you want to pay using a Cash only, or mixed combination of Cash and Debit/Prepaid Card or E-wallet.</li><li>Maximum amount allowed pay by Cash is IDR 2,5 Million, the rest should be combined using Debit/Prepaid Card or E-wallet.</li><li>Proceed to make a payment with the amount on your payment code/barcode</li></ol>', 29),
(1, 'Pembayaran via Gojek / GoPay', '<ol><li>Buka aplikasi Gojek / GoPay Anda.</li><li>Pilih menu <strong>Bayar / Scan</strong>.</li><li>Scan QR Code yang tampil di layar atau upload dari galeri.</li></ol>', 30),
(6, 'Pembayaran via Shopee', '<ol><li>Buka aplikasi Shopee Anda.</li><li>Pilih menu <strong>Bayar / Scan</strong>.</li><li>Scan QR Code yang tampil di layar atau upload dari galeri.</li></ol>', 31),
(7, 'Pembayaran via DANA', '<ol><li>Buka aplikasi DANA Anda.</li><li>Pilih menu <strong>Bayar / Scan</strong>.</li><li>Scan QR Code yang tampil di layar atau upload dari galeri.</li></ol>', 32),
(8, 'Pembayaran via LinkAja', '<ol><li>Buka aplikasi LinkAja Anda.</li><li>Pilih menu <strong>Bayar / Scan</strong>.</li><li>Scan QR Code yang tampil di layar atau upload dari galeri.</li></ol>', 33),
(5, 'Pembayaran via QRIS', '<ol><li>Buka aplikasi pembayaran pilihan Anda (GoPay, OVO, DANA, LinkAja, BCA Mobile, dll).</li><li>Pilih menu <strong>Scan / Bayar</strong>.</li><li>Scan QR Code yang tampil di layar.</li><li>Konfirmasi pembayaran dan masukkan PIN Anda.</li></ol>', 34);
